imitive Types Only"], "title": "Inference Type", "default": "None", "description": "How to infer the types of the columns. If none, inference default to strings.", "airbyte_hidden": true}, "header_definition": {"type": "object", "oneOf": [{"type": "object", "title": "From CSV", "required": ["header_definition_type"], "properties": {"header_definition_type": {"type": "string", "const": "From CSV", "title": "Header Definition Type", "default": "From CSV"}}}, {"type": "object", "title": "Autogenerated", "required": ["header_definition_type"], "properties": {"header_definition_type": {"type": "string", "const": "Autogenerated", "title": "Header Definition Type", "default": "Autogenerated"}}}, {"type": "object", "title": "User Provided", "required": ["column_names", "header_definition_type"], "properties": {"column_names": {"type": "array", "items": {"type": "string"}, "title": "Column Names", "description": "The column names that will be used while emitting the CSV records"}, "header_definition_type": {"type": "string", "const": "User Provided", "title": "Header Definition Type", "default": "User Provided"}}}], "title": "CSV Header Definition", "default": {"header_definition_type": "From CSV"}, "description": "How headers will be defined. `User Provided` assumes the CSV does not have a header row and uses the headers provided and `Autogenerated` assumes the CSV does not have a header row and the CDK will generate headers using for `f{i}` where `i` is the index starting from 0. Else, the default behavior is to use the header from the CSV file. If a user wants to autogenerate or provide column names for a CSV having headers, they can skip rows."}, "strings_can_be_null": {"type": "boolean", "title": "Strings Can Be Null", "default": true, "description": "Whether strings can be interpreted as null values. If true, strings that match the null_values set will be interpreted as null. If false, strings that match the null_values set will be interpreted as the string itself."}, "skip_rows_after_header": {"type": "integer", "title": "Skip Rows After Header", "default": 0, "description": "The number of rows to skip after the header row."}, "skip_rows_before_header": {"type": "integer", "title": "Skip Rows Before Header", "default": 0, "description": "The number of rows to skip before the header row. For example, if the header row is on the 3rd row, enter 2 in this field."}, "ignore_errors_on_fields_mismatch": {"type": "boolean", "title": "Ignore errors on field mismatch", "default": false, "description": "Whether to ignore errors that occur when the number of fields in the CSV does not match the number of columns in the schema."}}}, {"type": "object", "title": "Jsonl Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "jsonl", "title": "Filetype", "default": "jsonl"}}}, {"type": "object", "title": "Parquet Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "parquet", "title": "Filetype", "default": "parquet"}, "decimal_as_float": {"type": "boolean", "title": "Convert Decimal Fields to Floats", "default": false, "description": "Whether to convert decimal fields to floats. There is a loss of precision when converting decimals to floats, so this is not recommended."}}}, {"type": "object", "title": "Unstructured Document Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "unstructured", "title": "Filetype", "default": "unstructured"}, "strategy": {"enum": ["auto", "fast", "ocr_only", "hi_res"], "type": "string", "order": 0, "title": "Parsing Strategy", "default": "auto", "always_show": true, "description": "The strategy used to parse documents. `fast` extracts text directly from the document which doesn't work for all files. `ocr_only` is more reliable, but slower. `hi_res` is the most reliable, but requires an API key and a hosted instance of unstructured and can't be used with local mode. See the unstructured.io documentation for