r and decompressor memory requirements. Unless the uncompressed size of the file exceeds 8 MiB, 16 MiB, or 32 MiB, it is waste of memory to use the presets 7, 8, or 9, respectively. Read more <a href=\\"https://commons.apache.org/proper/commons-compress/apidocs/org/apache/commons/compress/compressors/xz/XZCompressorOutputStream.html#XZCompressorOutputStream-java.io.OutputStream-int-\\">here</a> for details."}}}, {"title": "zstandard", "required": ["codec"], "properties": {"codec": {"enum": ["zstandard"], "type": "string", "default": "zstandard"}, "include_checksum": {"type": "boolean", "title": "Include Checksum", "default": false, "description": "If true, include a checksum with each data block."}, "compression_level": {"type": "integer", "title": "Compression Level", "default": 3, "maximum": 22, "minimum": -5, "description": "Negative levels are 'fast' modes akin to lz4 or snappy, levels above 9 are generally for archival purposes, and levels above 18 use a lot of memory."}}}, {"title": "snappy", "required": ["codec"], "properties": {"codec": {"enum": ["snappy"], "type": "string", "default": "snappy"}}}], "title": "Compression Codec", "description": "The compression algorithm used to compress data. Default to no compression."}}}, {"title": "CSV: Comma-Separated Values", "required": ["format_type"], "properties": {"flattening": {"enum": ["No flattening", "Root level flattening"], "type": "string", "title": "Normalization", "default": "No flattening", "description": "Whether the input JSON data should be normalized (flattened) in the output CSV. Please refer to docs for details."}, "compression": {"type": "object", "oneOf": [{"title": "No Compression", "requires": ["compression_type"], "properties": {"compression_type": {"enum": ["No Compression"], "type": "string", "default": "No Compression"}}}, {"title": "GZIP", "requires": ["compression_type"], "properties": {"compression_type": {"enum": ["GZIP"], "type": "string", "default": "GZIP"}}}], "title": "Compression", 