le modified before this date will not be replicated.", "pattern_descriptor": "YYYY-MM-DD, YYYY-MM-DDTHH:mm:ssZ, or YYYY-MM-DDTHH:mm:ss.SSSSSSZ"}, "credentials": {"type": "object", "oneOf": [{"type": "object", "title": "Authenticate via Google (OAuth)", "required": ["client_id", "client_secret", "access_token", "refresh_token"], "properties": {"auth_type": {"enum": ["Client"], "type": "string", "const": "Client", "title": "Auth Type", "default": "Client"}, "client_id": {"type": "string", "title": "Client ID", "description": "Client ID", "airbyte_secret": true}, "access_token": {"type": "string", "title": "Access Token", "description": "Access Token", "airbyte_secret": true}, "client_secret": {"type": "string", "title": "Client Secret", "description": "Client Secret", "airbyte_secret": true}, "refresh_token": {"type": "string", "title": "Access Token", "description": "Access Token", "airbyte_secret": true}}}, {"type": "object", "title": "Service Account Authentication.", "required": ["service_account"], "properties": {"auth_type": {"enum": ["Service"], "type": "string", "const": "Service", "title": "Auth Type", "default": "Service"}, "service_account": {"type": "string", "title": "Service Account Information.", "description": "Enter your Google Cloud <a href=\\"https://cloud.google.com/iam/docs/creating-managing-service-account-keys#creating_service_account_keys\\">service account key</a> in JSON format", "airbyte_secret": true}}}], "order": 0, "title": "Authentication", "description": "Credentials for connecting to the Google Cloud Storage API"}, "delivery_method": {"type": "object", "group": "advanced", "oneOf": [{"type": "object", "title": "Replicate Records", "required": ["delivery_type"], "properties": {"delivery_type": {"enum": ["use_records_transfer"], "type": "string", "const": "use_records_transfer", "title": "Delivery Type", "default": "use_records_transfer"}}, "description": "Recommended - Extract and load structured records into your destination of choice.