er": {"type": "string", "title": "Delimiter", "default": ",", "description": "The character delimiting individual cells in the CSV data. This may only be a 1-character string. For tab-delimited data enter '\\\\t'."}, "quote_char": {"type": "string", "title": "Quote Character", "default": "\\"", "description": "The character used for quoting CSV values. To disallow quoting, make this field blank."}, "escape_char": {"type": "string", "title": "Escape Character", "description": "The character used for escaping special characters. To disallow escaping, leave this field blank."}, "null_values": {"type": "array", "items": {"type": "string"}, "title": "Null Values", "default": [], "description": "A set of case-sensitive strings that should be interpreted as null values. For example, if the value 'NA' should be interpreted as null, enter 'NA' in this field.", "uniqueItems": true}, "true_values": {"type": "array", "items": {"type": "string"}, "title": "True Values", "default": ["y", "yes", "t", "true", "on", "1"], "description": "A set of case-sensitive strings that should be interpreted as true values.", "uniqueItems": true}, "double_quote": {"type": "boolean", "title": "Double Quote", "default": true, "description": "Whether two quotes in a quoted CSV value denote a single quote in the data."}, "false_values": {"type": "array", "items": {"type": "string"}, "title": "False Values", "default": ["n", "no", "f", "false", "off", "0"], "description": "A set of case-sensitive strings that should be interpreted as false values.", "uniqueItems": true}, "header_definition": {"type": "object", "oneOf": [{"type": "object", "title": "From CSV", "required": ["header_definition_type"], "properties": {"header_definition_type": {"type": "string", "const": "From CSV", "title": "Header Definition Type", "default": "From CSV"}}}, {"type": "object", "title": "Autogenerated", "required": ["header_definition_type"], "properties": {"header_definition_type": {"type": "string", "const": "Autogenerated", "title": "Header Definition Type", "default": "Autogenerated"}}}, {"type": "object", "title": "User Provided", "required": ["column_names", "header_definition_type"], "properties": {"column_names": {"type": "array", "items": {"type": "string"}, "title": "Column Names", "description": "The column names that will be used while emitting the CSV records"}, "header_definition_type": {"type": "string", "const": "User Provided", "title": "Header Definition Type", "default": "User Provided"}}}], "title": "CSV Header Definition", "default": {"header_definition_type": "From CSV"}, "description": "How headers will be defined. `User Provided` assumes the CSV does not have a header row and uses the headers provided and `Autogenerated` assumes the CSV does not have a header row and the CDK will generate headers using for `f{i}` where `i` is the index starting from 0. Else, the default behavior is to use the header from the CSV file. If a user wants to autogenerate or provide column names for a CSV having headers, they can skip rows."}, "strings_can_be_null": {"type": "boolean", "title": "Strings Can Be Null", "default": true, "description": "Whether strings can be interpreted as null values. If true, strings that match the null_values set will be interpreted as null. If false, strings that match the null_values set will be interpreted as the string itself."}, "skip_rows_after_header": {"type": "integer", "title": "Skip Rows After Header", "default": 0, "description": "The number of rows to skip after the header row."}, "skip_rows_before_header": {"type": "integer", "title": "Skip Rows Before Header", "default": 0, "description": "The number of rows to skip before the header row. For example, if the header row is on the 3rd row, enter 2 in this field."}, "ignore_errors_on_fields_mismatch": {"type": "boolean", "title": "Ignore errors on field mismatch", "default": false, "description": "Whether to ignore errors that occur when the number of fields in the CSV does not match the number of columns in the schema."}}}, {"type": "object", "title": "Jsonl Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "jsonl", "title": "Filetype", "default": "jsonl"}}}, {"type": "object", "title": "Parquet Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "parquet", "title": "Filetype", "default": "parquet"}, "decimal_as_float": {"type": "boolean", "title": "Convert Decimal Fields to Floats", "default": false, "description": "Whether to convert decimal fields to floats. There is a loss of precision when converting decimals to floats, so this is not recommended."}}}, {"type": "object", "title": "Unstructured Document Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "unstructured", "title": "Filetype", "default": "unstructured"}, "strategy": {"enum": ["auto", "fast", "ocr_only", "hi_res"], "type": "string", "order": 0, "title": "Parsing Strategy", "default": "auto", "always_show": true, "description": "The strategy used to parse documents. `fast` extracts text directly from the document which doesn't work for all files. `ocr_only` is more reliable, but slower. `hi_res` is the most reliable, but requires an API key and a hosted instance of unstructured and can't be used with local mode. See the unstructured.io documentation for more details: https://unstructured-io.github.io/unstructured/core/partition.html#partition-pdf"}, "processing": {"type": "object", "oneOf": [{"type": "object", "title": "Local", "required": ["mode"], "properties": {"mode": {"enum": ["local"], "type": "string", "const": "local", "title": "Mode", "default": "local"}}, "description": "Process files locally, supporting `fast` and `ocr` modes. This is the default option."}], "title": "Processing", "default": {"mode": "local"}, "description": "Processing configuration"}, "skip_unprocessable_files": {"type": "boolean", "title": "Skip Unprocessable Files", "default": true, "always_show": true, "description": "If true, skip files that cannot be parsed and pass the error message along as the _ab_source_file_parse_error field. If false, fail the sync."}}, "description": "Extract text from document formats (.pdf, .docx, .md, .pptx) and emit as one record per file."}, {"type": "object", "title": "Excel Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "excel", "title": "Filetype", "default": "excel"}}}], "title": "Format", "description": "The configuration options that are used to alter how to read incoming files that deviate from the standard formatting."}, "schemaless": {"type": "boolean", "title": "Schemaless", "default": false, "description": "When enabled, syncs will not validate or structure records against the stream's schema."}, "primary_key": {"type": "string", "title": "Primary Key", "description": "The column or columns (for a composite key) that serves as the unique identifier of a record. If empty, the primary key will default to the parser's default primary key.", "airbyte_hidden": true}, "input_schema": {"type": "string", "title": "Input Schema", "description": "The schema that will be used to validate records extracted from the file. This will override the stream schema that is auto-detected from incoming files."}, "validation_policy": {"enum": ["Emit Record", "Skip Record", "Wait for Discover"], "title": "Validation Policy", "default": "Emit Record", "description": "The name of the validation policy that dictates sync behavior when a record does not adhere to the stream schema."}, "days_to_sync_if_history_is_full": {"type": "integer", "title": "Days To Sync If History Is Full", "default": 3, "description": "When the state history of the file store is full, syncs will only read files that were last modified in the provided day range."}, "use_first_found_file_for_schema_discovery": {"type": "boolean", "title": "Use First Found File For Schema Discover", "default": false, "description": "When enabled, the source will use the first found file for schema discovery. Helps to avoid long discovery step."}, "recent_n_files_to_read_for_schema_discovery": {"type": "integer", "title": "Files To Read For Schema Discover", "description": "The number of resent files which will be used to discover the schema for this stream.", "exclusiveMinimum": 0}}}, "order": 10, "title": "The list of streams to sync", "description": "Each instance of this configuration defines a <a href=\\"https://docs.airbyte.com/cloud/core-concepts#stream\\">stream</a>. Use this to define which files belong in the stream, their format, and how they should be parsed and validated. When sending data to warehouse destination such as Snowflake or BigQuery, each stream is a separate table."}, "site_url": {"type": "string", "order": 5, "title": "Site URL", "default": "", "description": "Url of SharePoint site to search for files. Leave empty to search in the main site. Use 'https://<tenant_name>.sharepoint.com/sites/' to iterate over all sites."}, "start_date": {"type": "string", "order": 1, "title": "Start Date", "format": "date-time", "pattern": "^[0-9]{4}-[0-9]{2}-[0-9]{2}(T[0-9]{2}:[0-9]{2}:[0-9]{2}(\\\\.[0-9]+)?(Z|[+-][0-9]{2}:[0-9]{2})?)?$", "examples": ["2021-01-01", "2021-01-01T00:00:00Z", "2021-01-01T00:00:00.000Z", "2021-01-01T00:00:00.000000Z"], "description": "UTC date and time in the format 2017-01-25T00:00:00.000000Z. Any file modified before this date will not be replicated.", "pattern_descriptor": "YYYY-MM-DD, YYYY-MM-DDTHH:mm:ssZ, or YYYY-MM-DDTHH:mm:ss.SSSSSSZ"}, "credentials": {"type": "object", "oneOf": [{"type": "object", "title": "Authenticate via Microsoft (OAuth)", "required": ["tenant_id", "client_id", "client_secret"], "properties": {"scopes": {"type": "string", "title": "Scopes", "default": "offline_access Files.Read.All Sites.Read.All Sites.Selected User.Read.All Group.Read.All Application.Read.All Device.Read.All", "description": "Scopes to request when authorizing. If you want to change scopes after source was created, you need to Re-authenticate to actually apply this change to your access token. "}, "auth_type": {"enum": ["Client"], "type": "string", "const": "Client", "title": "Auth Type", "default": "Client"}, "client_id": {"type": "string", "title": "Client ID", "description": "Client ID of your Microsoft developer application", "airbyte_secret": true}, "tenant_id": {"type": "string", "title": "Tenant ID", "description": "Tenant ID of the Microsoft SharePoint user", "airbyte_secret": true}, "client_secret": {"type": "string", "title": "Client Secret", "description": "Client Secret of your Microsoft developer application", "airbyte_secret": true}, "refresh_token": {"type": "string", "title": "Refresh Token", "description": "Refresh Token of your Microsoft developer application", "airbyte_secret": true}}, "description": "OAuthCredentials class to hold authentication details for Microsoft OAuth authentication.\\nThis class uses pydantic for data validation and settings management."}, {"type": "object", "title": "Service Key Authentication", "required": ["tenant_id", "user_principal_name", "client_id", "client_secret"], "properties": {"auth_type": {"enum": ["Service"], "type": "string", "const": "Service", "title": "Auth Type", "default": "Service"}, "client_id": {"type": "string", "title": "Client ID", "description": "Client ID of your Microsoft developer application", "airbyte_secret": true}, "tenant_id": {"type": "string", "title": "Tenant ID", "description": "Tenant ID of the Microsoft SharePoint user", "airbyte_secret": true}, "client_secret": {"type": "string", "title": "Client Secret", "description": "Client Secret of your Microsoft developer application", "airbyte_secret": true}, "user_principal_name": {"type": "string", "title": "User Principal Name", "description": "Special characters such as a period, comma, space, and the at sign (@) are converted to underscores (_). More details: https://learn.microsoft.com/en-us/