rows to skip after the header row."}, "skip_rows_before_header": {"type": "integer", "title": "Skip Rows Before Header", "default": 0, "description": "The number of rows to skip before the header row. For example, if the header row is on the 3rd row, enter 2 in this field."}, "ignore_errors_on_fields_mismatch": {"type": "boolean", "title": "Ignore errors on field mismatch", "default": false, "description": "Whether to ignore errors that occur when the number of fields in the CSV does not match the number of columns in the schema."}}}, {"type": "object", "title": "Jsonl Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "jsonl", "title": "Filetype", "default": "jsonl"}}}, {"type": "object", "title": "Parquet Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "parquet", "title": "Filetype", "default": "parquet"}, "decimal_as_float": {"type": "boolean", "title": "Convert Decimal Fields to Floats", "default": false, "description": "Whether to convert decimal fields to floats. There is a loss of precision when converting decimals to floats, so this is not recommended."}}}, {"type": "object", "title": "Unstructured Document Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "unstructured", "title": "Filetype", "default": "unstructured"}, "strategy": {"enum": ["auto", "fast", "ocr_only", "hi_res"], "type": "string", "order": 0, "title": "Parsing Strategy", "default": "auto", "always_show": true, "description": "The strategy used to parse documents. `fast` extracts text directly from the document which doesn't work for all files. `ocr_only` is more reliable, but slower. `hi_res` is the most reliable, but requires an API key and a hosted instance of unstructured and can't be used with local mode. See the unstructured.io documentation for more details: https://unstructured-io.github.io/unstructured/core/partition.html#partition-pdf"}, "processing": {"type": "object", "oneOf": [{"type": "object", "title": "Local", "required": ["mode"], "properties": {"mode": {"enum": ["local"], "type": "string", "const": "local", "title": "Mode", "default": "local"}}, "description": "Process files locally, supporting `fast` and `ocr` modes. This is the default option."}], "title": "Processing", "default": {"mode": "local"}, "description": "Processing configuration"}, "skip_unprocessable_files": {"type": "boolean", "title": "Skip Unprocessable Files", "default": true, "always_show": true, "description": "If true, skip files that cannot be parsed and pass the error message along as the _ab_source_file_parse_error field. If false, fail the sync."}}, "description": "Extract text from document formats (.pdf, .docx, .md, .pptx) and emit as one record per file."}, {"type": "object", "title": "Excel Format", "required": ["filetype"], "properties": {"filetype": {"type": "string", "const": "excel", "title": "Filetype", "default": "excel"}}}], "title": "Format", "description": "The configuration options that are used to alter how to read incoming files that deviate from the standard formatting."}, "schemaless": {"type": "boolean", "title": "Schemaless", "default": false, "description": "When enabled, syncs will not validate or structure records against the stream's schema."}, "primary_key": {"type": "string", "title": "Primary Key", "description": "The column or columns (for a composite key) that serves as the unique identifier of a record. If empty, the primary key will default to the parser's default primary key.", "airbyte_hidden": true}, "input_schema": {"type": "string", "title": "Input Schema", "description": "The schema that will be used to validate records extracted from the file. This will override the stream schema that is auto-detected from incoming files."}, "legacy_prefix": {"type": "string", "title": "Legacy Prefix", "description": "The path prefix configured in v3 versions of the S3 connector. This option is deprecated in favor of a si