ned by the lookup, even if the lookup returns multiple IP addresses."}, "enable_auto_commit": {"type": "boolean", "title": "Enable Auto Commit", "default": true, "description": "If true, the consumer's offset will be periodically committed in the background."}, "request_timeout_ms": {"type": "integer", "title": "Request Timeout, ms", "default": 30000, "description": "The configuration controls the maximum amount of time the client will wait for the response of a request. If the response is not received before the timeout elapses the client will resend the request if necessary or fail the request if retries are exhausted."}, "max_records_process": {"type": "integer", "title": "Maximum Records", "default": 100000, "description": "The Maximum to be processed per execution"}, "receive_buffer_bytes": {"type": "integer", "title": "Receive Buffer, bytes", "default": 32768, "description": "The size of the TCP receive buffer (SO_RCVBUF) to use when reading data. If the value is -1, the OS default will be used."}, "auto_commit_interval_ms": {"type": "integer", "title": "Auto Commit Interval, ms", "default": 5000, "description": "The frequency in milliseconds that the consumer offsets are auto-committed to Kafka if enable.auto.commit is set to true."}}, "additionalProperties": true}, "supported_source_sync_modes": ["append"], "supported_destination_sync_modes": []}	0.2.0	\N	\N	\N	\N	\N	\N	\N	alpha	supported	community	f	\N	2025-11-19 02:11:19.655+00	100	java	f	f	\N
