": "Pre-Load Value Validation", "default": false, "examples": ["false"], "always_show": false, "description": "When enabled, Airbyte will validate all values before loading them into the destination table. This provides stronger data integrity guarantees but may significantly impact performance."}}, "description": "Configuration details for using the BULK loading mechanism.", "additionalProperties": true}], "order": 8, "title": "Load Type", "always_show": true, "description": "Specifies the type of load mechanism (e.g., BULK, INSERT) and its associated configuration."}, "ssl_method": {"type": "object", "oneOf": [{"type": "object", "title": "Unencrypted", "required": ["name"], "properties": {"name": {"enum": ["unencrypted"], "type": "string", "default": "unencrypted"}}, "description": "The data transfer will not be encrypted.", "additionalProperties": true}, {"type": "object", "title": "Encrypted (trust server certificate)", "required": ["name"], "properties": {"name": {"enum": ["encrypted_trust_server_certificate"], "type": "string", "default": "encrypted_trust_server_certificate"}}, "description": "Use the certificate provided by the server without verification. (For testing purposes only!)", "additionalProperties": true}, {"type": "object", "title": "Encrypted (verify certificate)", "required": ["name"], "properties": {"name": {"enum": ["encrypted_verify_certificate"], "type": "string", "default": "encrypted_verify_certificate"}, "trustStoreName": {"type": "string", "order": 1, "title": "Trust Store Name", "description": "Specifies the name of the trust store."}, "trustStorePassword": {"type": "string", "order": 2, "title": "Trust Store Password", "description": "Specifies the password of the trust store.", "airbyte_secret": true}, "hostNameInCertificate": {"type": "string", "order": 3, "title": "Host Name In Certificate", "description": "Specifies the host name of the server. The value of this property must match the subject property of the certificate."}}, "description": "Verify and use the certificate provided by the server.", "additionalProperties": true}], "order": 7, "title": "SSL Method", "description": "The encryption method which is used to communicate with the database."}, "tunnel_method": {"type": "object", "oneOf": [{"type": "object", "title": "No Tunnel", "required": ["tunnel_method"], "properties": {"tunnel_method": {"enum": ["NO_TUNNEL"], "type": "string", "default": "NO_TUNNEL"}}, "description": "No ssh tunnel needed to connect to database", "additionalProperties": true}, {"type": "object", "title": "SSH Key Authentication", "required": ["tunnel_method", "tunnel_host", "tunnel_port", "tunnel_user", "ssh_key"], "properties": {"ssh_key": {"type": "string", "order": 4, "title": "SSH Private Key", "multiline": true, "description": "OS-level user account ssh key credentials in RSA PEM format ( created with ssh-keygen -t rsa -m PEM -f myuser_rsa )", "airbyte_secret": true}, "tunnel_host": {"type": "string", "order": 1, "title": "SSH Tunnel Jump Server Host", "description": "Hostname of the jump server host that allows inbound ssh tunnel."}, "tunnel_port": {"type": "integer", "order": 2, "title": "SSH Connection Port", "default": 22, "maximum": 65536, "minimum": 0, "description": "Port on the proxy/jump server that accepts inbound ssh connections."}, "tunnel_user": {"type": "string", "order": 3, "title": "SSH Login Username", "description": "OS-level username for logging into the jump server host"}, "tunnel_method": {"enum": ["SSH_KEY_AUTH"], "type": "string", "default": "SSH_KEY_AUTH"}}, "description": "Connect through a jump server tunnel host using username and ssh key", "additionalProperties": true}, {"type": "object", "title": "Password Authentication", "required": ["tunnel_method", "tunnel_host", "tunnel_port", "tunnel_user", "tunnel_user_password"], "properties": {"tunnel_host": {"type": "string", "order": 1, "title": "SSH Tunnel Jump Server Host", "description": "Hostname of the jump server host that allows 