ult": "verify-full"}, "ssl_ca_certificate": {"type": "string", "order": 1, "title": "CA certificate", "multiline": true, "description": "Specifies the file name of a PEM file that contains Certificate Authority (CA) certificates for use with SSLMODE=verify-full.\\n See more information - <a href=\\"https://teradata-docs.s3.amazonaws.com/doc/connectivity/jdbc/reference/current/jdbcug_chapter_2.html#URL_SSLCA\\"> in the docs</a>.", "airbyte_secret": true}}, "description": "Verify-full SSL mode.", "additionalProperties": false}], "order": 4, "title": "SSL modes", "description": "SSL connection modes. \\n <b>disable</b> - Chose this mode to disable encryption of communication between Airbyte and destination database\\n <b>allow</b> - Chose this mode to enable encryption only when required by the destination database\\n <b>prefer</b> - Chose this mode to allow unencrypted connection only if the destination database does not support encryption\\n <b>require</b> - Chose this mode to always require encryption. If the destination database server does not support encryption, connection will fail\\n  <b>verify-ca</b> - Chose this mode to always require encryption and to verify that the destination database server has a valid SSL certificate\\n  <b>verify-full</b> - This is the most secure mode. Chose this mode to always require encryption and to verify the identity of the destination database server\\n See more information - <a href=\\"https://teradata-docs.s3.amazonaws.com/doc/connectivity/jdbc/reference/current/jdbcug_chapter_2.html#URL_SSLMODE\\"> in the docs</a>."}, "query_band": {"type": "string", "order": 5, "title": "Query Band", "description": "Defines the custom session query band using name-value pairs. For example, 'org=Finance;report=Fin123;'"}, "drop_cascade": {"type": "boolean", "order": 9, "title": "Drop tables with CASCADE. (WARNING! Risk of unrecoverable data loss)", "default": false, "description": "Drop tables with CASCADE. WARNING! This will delete all data