re"}, "cohere_key": {"type": "string", "title": "Cohere API key", "airbyte_secret": true}}, "description": "Use the Cohere API to embed text."}, {"type": "object", "title": "From Field", "required": ["field_name", "dimensions", "mode"], "properties": {"mode": {"enum": ["from_field"], "type": "string", "const": "from_field", "title": "Mode", "default": "from_field"}, "dimensions": {"type": "integer", "title": "Embedding dimensions", "examples": [1536, 384], "description": "The number of dimensions the embedding model is generating"}, "field_name": {"type": "string", "title": "Field name", "examples": ["embedding", "vector"], "description": "Name of the field in the record that contains the embedding"}}, "description": "Use a field in the record as the embedding. This is useful if you already have an embedding for your data and want to store it in the vector store."}, {"type": "object", "title": "Fake", "required": ["mode"], "properties": {"mode": {"enum": ["fake"], "type": "string", "const": "fake", "title": "Mode", "default": "fake"}}, "description": "Use a fake embedding made out of random vectors with 1536 embedding dimensions. This is useful for testing the data pipeline without incurring any costs."}, {"type": "object", "title": "OpenAI-compatible", "required": ["base_url", "dimensions", "mode"], "properties": {"mode": {"enum": ["openai_compatible"], "type": "string", "const": "openai_compatible", "title": "Mode", "default": "openai_compatible"}, "api_key": {"type": "string", "title": "API key", "default": "", "airbyte_secret": true}, "base_url": {"type": "string", "title": "Base URL", "examples": ["https://your-service-name.com"], "description": "The base URL for your OpenAI-compatible service"}, "dimensions": {"type": "integer", "title": "Embedding dimensions", "examples": [1536, 384], "description": "The number of dimensions the embedding model is generating"}, "model_name": {"type": "string", "title": "Model name", "default": "text-embedding-ada-002", "examples": ["text-embedding-ada-002"], "description": "The name of the model to use for embedding"}}, "description": "Use a service that's compatible with the OpenAI API to embed text."}], "title": "Embedding", "description": "Embedding configuration"}, "processing": {"type": "object", "group": "processing", "title": "ProcessingConfigModel", "required": ["chunk_size"], "properties": {"chunk_size": {"type": "integer", "title": "Chunk size", "maximum": 8191, "minimum": 1, "description": "Size of chunks in tokens to store in vector store (make sure it is not too big for the context if your LLM)"}, "text_fields": {"type": "array", "items": {"type": "string"}, "title": "Text fields to embed", "default": [], "examples": ["text", "user.name", "users.*.name"], "always_show": true, "description": "List of fields in the record that should be used to calculate the embedding. The field list is applied to all streams in the same way and non-existing fields are ignored. If none are defined, all fields are considered text fields. When specifying text fields, you can access nested fields in the record by using dot notation, e.g. `user.name` will access the `name` field in the `user` object. It's also possible to use wildcards to access all fields in an object, e.g. `users.*.name` will access all `names` fields in all entries of the `users` array."}, "chunk_overlap": {"type": "integer", "title": "Chunk overlap", "default": 0, "description": "Size of overlap between chunks in tokens to store in vector store to better capture relevant context"}, "text_splitter": {"type": "object", "oneOf": [{"type": "object", "title": "By Separator", "required": ["mode"], "properties": {"mode": {"enum": ["separator"], "type": "string", "const": "separator", "title": "Mode", "default": "separator"}, "separators": {"type": "array", "items": {"type": "string"}, "title": "Separators", "default": ["\\"\\\\n\\\\n\\"", "\\"\\\\n\\"", "\\" \\"", "\\"\\""], "description": "List of separator strings to split text fields by. The separator itself needs to be wrapped in double quotes, e.g. to split by the dot character, use \\".\\". To split by a newline, use \\"\\\\n\\"."}, "keep_separator": {"type": "boolean", "title": "Keep separator", "default": false, "description": "Whether to keep the separator in the resulting chunks"}}, "description": "Split the text by the list of separators until the chunk size is reached, using the earlier mentioned separators where possible. This is useful for splitting text fields by paragraphs, sentences, words, etc."}, {"type": "object", "title": "By Markdown header", "required": ["mode"], "properties": {"mode": {"enum": ["markdown"], "type": "string", "const": "markdown", "title": "Mode", "default": "markdown"}, "split_level": {"type": "integer", "title": "Split level", "default": 1, "maximum": 6, "minimum": 1, "description": "Level of markdown headers to split text fields by. Headings down to the specified level will be used as split points"}}, "description": "Split the text by Markdown headers down to the specified header level. If the chunk size fits multiple sections, they will be combined into a single chunk."}, {"type": "object", "title": "By Programming Language", "required": ["language", "mode"], "properties": {"mode": {"enum": ["code"], "type": "string", "const": "code", "title": "Mode", "default": "code"}, "language": {"enum": ["cpp", "go", "java", "js", "php", "proto", "python", "rst", "ruby", "rust", "scala", "swift", "markdown", "latex", "html", "sol"], "type": "string", "title": "Language", "description": "Split code in suitable places based on the programming language"}}, "description": "Split the text by suitable delimiters based on the programming language. This is useful for splitting code into chunks."}], "title": "Text splitter", "description": "Split text fields into chunks based on the specified method."}, "metadata_fields": {"type": "array", "items": {"type": "string"}, "title": "Fields to store as metadata", "default": [],